  private JSONObject getGSuiteUsersByOU(String orgUnitPath, String urlStr) {

    org.json.JSONObject jsonObject = null;
    token = context.decrypt(jobj); //Passed in via global variable (Rule-GSuite-AccessToken).
    //String urlStr = null;

