  private List parseOrgJson(JSONObject jsonObject) throws IOException, JSONException {

    List<String> list = new ArrayList<String>();
    org.json.JSONArray jsonArray = jsonObject.getJSONArray("users");
    for(int i = 0 ; i < jsonArray.length(); i++) {

      list.add(jsonArray.getJSONObject(i).getString("primaryEmail"));

    }
    return list;
  }


  private String getAPIUrl(String nextPageToken, String orgUnitPath){

    String customer = "my_customer";
    String query = "orgUnitPath=" + orgUnitPath;
    String fields = "users(primaryEmail),nextPageToken";
    String urlStr = null;
    if(nextPageToken == null || nextPageToken == ""){
      urlStr = "https://admin.googleapis.com/admin/directory/v1/users?customer=" + customer + "&query=" + query + "&fields=" + fields;
    }else{
      urlStr = "https://admin.googleapis.com/admin/directory/v1/users?customer=" + customer + "&query=" + query + "&fields=" + fields + "&pageToken=" + nextPageToken;
    }
    return urlStr;
  }

  public List executeJSONCall(String orgUnitPath){
    System.out.println("Entering executeJSONCall");
    org.json.JSONObject jo = null;
    String urlStr = null;
    List parsedList = new ArrayList();
    do {
    if(nextPageToken == null || nextPageToken == ""){
      System.out.println("nextPageToken is NULL - Continuing");
      urlStr = getAPIUrl("", orgUnitPath);
      jo = getGSuiteUsersByOU(orgUnitPath, urlStr);
      nextPageToken = jo.getString("nextPageToken");
      System.out.println("nextPageToken-original: " + nextPageToken);
      parsedList = parseOrgJson(jo);
    }else{
      System.out.println("nextPageToken is NOT NULL - Continuing");
      System.out.println("nextPageToken-new: " + nextPageToken);
      //do {
        urlStr = getAPIUrl(nextPageToken, orgUnitPath);
        jo = getGSuiteUsersByOU(orgUnitPath, urlStr);
        nextPageToken = jo.getString("nextPageToken");
        parsedList = parseOrgJson(jo);

      //}while(nextPageToken != "");
    }
    }while(nextPageToken != "");
    System.out.println("parsedList: " + parsedList);
    return parsedList;
  }
